import { readFile } from 'node:fs/promises';
import { resolve } from 'node:path';
export async function projectPaths(cwd = process.cwd()) {
    const projectDirectory = resolve(cwd);
    try {
        const config = JSON.parse(await readFile(resolve(projectDirectory, 'geckokit.json'), 'utf8'));
        if (typeof config.firefoxSource !== 'string' || config.firefoxSource.length === 0) {
            throw new Error('firefoxSource must be a non-empty string');
        }
        return {
            projectDirectory,
            firefoxSource: resolve(projectDirectory, config.firefoxSource),
        };
    }
    catch (error) {
        throw new Error(`Invalid geckokit.json: ${error instanceof Error ? error.message : String(error)}`);
    }
}
